input.oldString:
alchemyResponse.data.tokens.forEach((token: unknown) => {
  const tokenData = token as { tokenAddress?: string; tokenMetadata?: { symbol?: string; name?: string; decimals?: number; logo?: string } }
  if (token.tokenAddress && token.tokenAddress !== '0x0000000000000000000000000000000000000000') {
    const addr = token.tokenAddress.toLowerCase()
    tokenAddressSet.add(addr)

    tokenMetadata.set(addr, {
      address: token.tokenAddress,
      symbol: token.tokenMetadata?.symbol || 'UNKNOWN',
      name: token.tokenMetadata?.name || 'Unknown Token',
      decimals: token.tokenMetadata?.decimals || 18,
      chainId: revokeChain.id,
      metadata: token.tokenMetadata?.logo ? { logoURI: token.tokenMetadata.logo } : undefined,
    })
  }
})

